{"code": "from hermes_tools import terminal
import os, re

articles_dir = r"C:\HermesPortable\home\spaces\hostazar\artikel"

# Get all article HTML files
html_files = [f for f in os.listdir(articles_dir) if f.endswith(".html")]
html_slugs = {f.replace(".html", "") for f in html_files}

# Get all sitemap entries
with open(r"C:\HermesPortable\home\spaces\hostazar\sitemap.xml") as f:
    sitemap = f.read()
sitemap_slugs = set(re.findall(r'artikel/([^<]+)\.html', sitemap))

# Missing articles (in files but not in sitemap)
missing_from_sitemap = html_slugs - sitemap_slugs
# Orphan sitemap entries (in sitemap but no file)
orphan_sitemap = sitemap_slugs - html_slugs

print(f"=== Coverage ===")
print(f"HTML files: {len(html_files)}")
print(f"Sitemap entries: {len(sitemap_slugs)}")
print(f"")

if missing_from_sitemap:
    print(f"❌ In HTML but NOT in sitemap ({len(missing_from_sitemap)}):")
    for s in sorted(missing_from_sitemap): print(f"  - {s}")
else:
    print(f"✅ All article HTMLs are in sitemap")

if orphan_sitemap:
    print(f"❌ Sitemap entries with NO HTML file ({len(orphan_sitemap)}):")
    for s in sorted(orphan_sitemap): print(f"  - {s}")
else:
    print(f"✅ No orphan sitemap entries")

# Check OG images per article
poor_og = []
for fname in sorted(html_files):
    path = os.path.join(articles_dir, fname)
    with open(path) as f:
        content = f.read()
    match = re.search(r'<meta property="og:image" content="([^"]+)"', content)
    if match:
        url = match.group(1)
        if "/images/" not in url and url == "https://hostazar.com/og-image.png":
            poor_og.append((fname, url))
    else:
        poor_og.append((fname, "MISSING"))

if poor_og:
    print(f"\n❌ Articles still on default/old OG image ({len(poor_og)}):")
    for f, url in poor_og:
        print(f"  {f}: {url}")
else:
    print(f"\n✅ All articles have dedicated OG images")

# Check Twitter cards
no_twitter = []
for fname in sorted(html_files):
    path = os.path.join(articles_dir, fname)
    with open(path) as f:
        content = f.read()
    if 'twitter:card' not in content:
        no_twitter.append(fname)

if no_twitter:
    print(f"\n⚠️ Missing twitter:card ({len(no_twitter)} articles):")
    for f in no_twitter[:5]: print(f"  {f}")
    if len(no_twitter) > 5: print(f"  ... and {len(no_twitter)-5} more")
else:
    print(f"\n✅ All articles have Twitter cards")
"}

